module top_module(
  input [15:0]      obf_a,
  input [15:0]      b,
  input [15:0]      c,
  input [2:0]       sel,
  output reg [31:0] res
  );always @* begin
    case(sel)
      0: res = {obf_a + b, obf_a};
      1: res = {obf_a - b, b};
      2: res = {obf_a + c, c};
      3: res = {obf_a - c, obf_a};
      4: res = {b, b};
      5: res = {c, c};
      default: res = 32'bx;
    endcase
  end

endmodule
